class Parent:
    def __init__(self, attr):
        self.attr = attr

    def method(self):
        return f"Parent method with {self.attr}"

class Child(Parent):
    def __init__(self, attr, extra):
        super().__init__(attr)
        self.extra = extra

    def method(self):
        return f"Child overridden: {self.attr}, {self.extra}"

    def child_method(self):
        return "Only in child"
